/** A connection to a list of `ZslRound` values. */
export interface ZslRoundsConnection {
	/** A list of `ZslRound` objects. */
	nodes: ZslRound[];
	/** A list of edges which contains the `ZslRound` and cursor to aid in pagination. */
	edges: ZslRoundsEdge[];
	/** Information to aid in pagination. */
	pageInfo: PageInfo;
	/** The count of *all* `ZslRound` you could get from the connection. */
	totalCount: Scalars['Int'];
	/** Aggregates across the matching connection (ignoring before/after/first/last/offset) */
	aggregates: ZslRoundAggregates | null;
	/** Grouped aggregates across the matching connection (ignoring before/after/first/last/offset) */
	groupedAggregates: ZslRoundAggregates[] | null;
	__typename: 'ZslRoundsConnection';
}

/** A `ZslRound` edge in the connection. */
export interface ZslRoundsEdge {
	/** A cursor for use in pagination. */
	cursor: Scalars['Cursor'] | null;
	/** The `ZslRound` at the end of the edge. */
	node: ZslRound;
	__typename: 'ZslRoundsEdge';
}

export interface ZslRoundAggregates {
	keys: Scalars['String'][] | null;
	/** Sum aggregates across the matching connection (ignoring before/after/first/last/offset) */
	sum: ZslRoundSumAggregates | null;
	/** Distinct count aggregates across the matching connection (ignoring before/after/first/last/offset) */
	distinctCount: ZslRoundDistinctCountAggregates | null;
	/** Minimum aggregates across the matching connection (ignoring before/after/first/last/offset) */
	min: ZslRoundMinAggregates | null;
	/** Maximum aggregates across the matching connection (ignoring before/after/first/last/offset) */
	max: ZslRoundMaxAggregates | null;
	/** Mean average aggregates across the matching connection (ignoring before/after/first/last/offset) */
	average: ZslRoundAverageAggregates | null;
	/** Sample standard deviation aggregates across the matching connection (ignoring before/after/first/last/offset) */
	stddevSample: ZslRoundStddevSampleAggregates | null;
	/** Population standard deviation aggregates across the matching connection (ignoring before/after/first/last/offset) */
	stddevPopulation: ZslRoundStddevPopulationAggregates | null;
	/** Sample variance aggregates across the matching connection (ignoring before/after/first/last/offset) */
	varianceSample: ZslRoundVarianceSampleAggregates | null;
	/** Population variance aggregates across the matching connection (ignoring before/after/first/last/offset) */
	variancePopulation: ZslRoundVariancePopulationAggregates | null;
	__typename: 'ZslRoundAggregates';
}

